    \node[font=\Large\bfseries, color=zfred] at (1.5, 0.85) {$F$};
    \node[font=\Large\bfseries, color=zfgreen] at (2.5, 0.85) {$s$};
\end{tikzpicture}\\[1mm]
{\scriptsize zakryj veličinu, kterou hledáš}
\end{center}
