\vspace{2mm}
\noindent
\textbf{Pozn.:} Vzorec platí, když síla \textbf{působí ve směru pohybu}.

\vspace{4mm}
{\Large \bfseries \color{zfblue} Kdy se práce koná}
\vspace{2mm}

\begin{center}
